import { Component, ChangeDetectionStrategy, input, computed } from '@angular/core';
import { NgTemplateOutlet } from '@angular/common';
import { mergeClasses } from '../../utils/merge-classes';
import { ImageComponent } from '../image/image.component';
import { avatarVariants, SIZE_PX, type AvatarVariants } from './avatar.variants';
import { STATUS_COLOR, STATUS_LABEL, type AvatarStatus } from './avatar.status';

@Component({
  selector: 'n-avatar',
  standalone: true,
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [ImageComponent, NgTemplateOutlet],
  template: `
    <span class="absolute inset-0 overflow-hidden rounded-[inherit]">
      @if (nSrc()) {
        <n-image
          [nSrc]="nSrc()"
          nAlt=""
          nFit="cover"
          [nFill]="true"
          [nSkeleton]="false"
          nClass="size-full"
        >
          <ng-container nImageFallback>
            <ng-container *ngTemplateOutlet="fallback" />
          </ng-container>
        </n-image>
      } @else {
        <ng-container *ngTemplateOutlet="fallback" />
      }
    </span>

    @if (nStatus()) {
      <span
        class="absolute right-0 bottom-0 rounded-full ring-2 ring-background"
        [style.width]="statusDotSize()"
        [style.height]="statusDotSize()"
        [style.background-color]="statusColorValue()"
        role="img"
        [attr.aria-label]="statusLabelValue()"
      ></span>
    }

    <ng-content />

    <ng-template #fallback>
      <span
        data-slot="fallback"
        class="flex size-full items-center justify-center font-medium select-none"
        [style.background]="fallbackBg()"
        [style.color]="fallbackText()"
        [style.font-size]="fallbackFontSize()"
        aria-hidden="true"
      >{{ initials() || defaultIcon }}</span>
    </ng-template>
  `,
  host: {
    '[class]':           'classes()',
    '[attr.role]':       '"img"',
    '[attr.aria-label]': 'ariaLabel()',
  },
})
export class AvatarComponent {
  readonly nSrc       = input<string>('');
  readonly nName      = input<string>('');
  readonly nSize      = input<AvatarVariants['nSize']>('default');
  readonly nShape     = input<AvatarVariants['nShape']>('circle');
  readonly nStatus    = input<AvatarStatus | null>(null);
  readonly nClass     = input<string>('');
  readonly nAriaLabel = input<string>('');

  protected readonly defaultIcon = '?';

  protected readonly classes = computed(() =>
    mergeClasses(
      avatarVariants({ nSize: this.nSize(), nShape: this.nShape() }),
      this.nClass(),
    ),
  );

  protected readonly sizePixels = computed(() =>
    SIZE_PX[this.nSize() ?? 'default'],
  );

  protected readonly initials = computed(() => {
    const name = this.nName().trim();
    if (!name) return '';
    const parts = name.split(/\s+/).filter(Boolean);
    if (parts.length === 1) return parts[0].slice(0, 2).toUpperCase();
    return (parts[0][0] + parts[parts.length - 1][0]).toUpperCase();
  });

  private readonly fallbackHue = computed(() => {
    const name = this.nName() || '?';
    let hash = 0;
    for (let i = 0; i < name.length; i++) {
      hash = name.charCodeAt(i) + ((hash << 5) - hash);
    }
    return Math.abs(hash) % 360;
  });

  protected readonly fallbackBg = computed(() => `hsl(${this.fallbackHue()}, 55%, 45%)`);

  // Texto branco ou preto conforme luminância da cor gerada — hues claros (amarelo)
  // não têm contraste suficiente contra branco em L=45%.
  protected readonly fallbackText = computed(() =>
    luminance(this.fallbackHue(), 0.55, 0.45) > 0.45 ? '#000' : '#fff',
  );

  protected readonly fallbackFontSize = computed(() => {
    const px = this.sizePixels();
    return `${Math.round(px * 0.38)}px`;
  });

  protected readonly statusDotSize = computed(() => {
    const px = this.sizePixels();
    return `${Math.max(8, Math.round(px * 0.28))}px`;
  });

  protected readonly statusColorValue = computed(() => {
    const s = this.nStatus();
    return s ? STATUS_COLOR[s] : '';
  });

  protected readonly statusLabelValue = computed(() => {
    const s = this.nStatus();
    return s ? STATUS_LABEL[s] : '';
  });

  protected readonly ariaLabel = computed(() =>
    this.nAriaLabel() || (this.nName() ? `Avatar de ${this.nName()}` : 'Avatar'),
  );
}

function luminance(h: number, s: number, l: number): number {
  const c = (1 - Math.abs(2 * l - 1)) * s;
  const hp = h / 60;
  const x = c * (1 - Math.abs((hp % 2) - 1));
  const m = l - c / 2;
  let r = 0, g = 0, b = 0;
  if (hp < 1)      [r, g, b] = [c, x, 0];
  else if (hp < 2) [r, g, b] = [x, c, 0];
  else if (hp < 3) [r, g, b] = [0, c, x];
  else if (hp < 4) [r, g, b] = [0, x, c];
  else if (hp < 5) [r, g, b] = [x, 0, c];
  else             [r, g, b] = [c, 0, x];
  return 0.2126 * (r + m) + 0.7152 * (g + m) + 0.0722 * (b + m);
}

import { Component, ChangeDetectionStrategy, input, computed } from '@angular/core';
import { AvatarComponent } from './avatar.component';
import { type AvatarVariants, SIZE_PX, SIZE_CLASSES, SHAPE_CLASSES } from './avatar.variants';
import { STATUS_COLOR, STATUS_LABEL, type AvatarStatus } from './avatar.status';
import { mergeClasses } from '../../utils/merge-classes';

export type AvatarGroupItem = {
  src?:    string;
  name?:   string;
  status?: AvatarStatus;
};

@Component({
  selector: 'n-avatar-group',
  standalone: true,
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [AvatarComponent],
  template: `
    @for (item of visibleItems(); track item.src ?? item.name ?? $index) {
      <n-avatar
        [nSrc]="item.src ?? ''"
        [nName]="item.name ?? ''"
        [nSize]="nSize()"
        [nShape]="nShape()"
        class="-ml-2 ring-2 ring-background first:ml-0 transition-all duration-200 hover:-translate-y-1 hover:z-10"
      >
        @if (item.status) {
          <span
            class="absolute right-0 bottom-0 rounded-full ring-2 ring-background"
            [style.width]="badgeDotSize()"
            [style.height]="badgeDotSize()"
            [style.background-color]="statusColor(item.status)"
            role="img"
            [attr.aria-label]="statusLabel(item.status)"
          ></span>
        }
      </n-avatar>
    }
    @if (overflowCount() > 0) {
      <div
        class="-ml-2 inline-flex shrink-0 items-center justify-center bg-muted text-muted-foreground font-medium ring-2 ring-background select-none transition-all duration-200 hover:-translate-y-1 hover:z-10"
        [class]="overflowClasses()"
        [style.font-size]="overflowFontSize()"
        role="img"
        [attr.aria-label]="'+' + overflowCount() + ' outros'"
      >+{{ overflowCount() }}</div>
    }
  `,
  host: {
    '[class]':           'classes()',
    '[attr.role]':       '"group"',
    '[attr.aria-label]': 'nAriaLabel()',
  },
})
export class AvatarGroupComponent {
  readonly nItems     = input<AvatarGroupItem[]>([]);
  readonly nMax       = input<number>(5);
  readonly nSize      = input<AvatarVariants['nSize']>('default');
  readonly nShape     = input<AvatarVariants['nShape']>('circle');
  readonly nClass     = input<string>('');
  readonly nAriaLabel = input<string>('Grupo de avatares');

  protected readonly classes = computed(() =>
    mergeClasses('flex items-center', this.nClass()),
  );

  protected readonly visibleItems = computed(() =>
    this.nItems().slice(0, this.nMax()),
  );

  protected readonly overflowCount = computed(() =>
    Math.max(0, this.nItems().length - this.nMax()),
  );

  protected readonly overflowClasses = computed(() =>
    mergeClasses(
      SIZE_CLASSES[this.nSize() ?? 'default'],
      SHAPE_CLASSES[this.nShape() ?? 'circle'],
    ),
  );

  protected readonly overflowFontSize = computed(() => {
    const px = SIZE_PX[this.nSize() ?? 'default'];
    return `${Math.round(px * 0.32)}px`;
  });

  protected readonly badgeDotSize = computed(() => {
    const px = SIZE_PX[this.nSize() ?? 'default'];
    return `${Math.max(8, Math.round(px * 0.28))}px`;
  });

  protected statusColor(status: AvatarStatus): string {
    return STATUS_COLOR[status];
  }

  protected statusLabel(status: AvatarStatus): string {
    return STATUS_LABEL[status];
  }
}

import { cva, type VariantProps } from 'class-variance-authority';

export const avatarVariants = cva(
  'relative inline-flex shrink-0',
  {
    variants: {
      nSize: {
        xs:      'size-6',
        sm:      'size-8',
        default: 'size-10',
        lg:      'size-12',
        xl:      'size-16',
      },
      nShape: {
        circle: 'rounded-full',
        square: 'rounded-md',
      },
    },
    defaultVariants: {
      nSize:  'default',
      nShape: 'circle',
    },
  },
);

export type AvatarVariants = VariantProps<typeof avatarVariants>;

export const SIZE_PX: Record<NonNullable<AvatarVariants['nSize']>, number> = {
  xs:      24,
  sm:      32,
  default: 40,
  lg:      48,
  xl:      64,
};

export const SIZE_CLASSES: Record<NonNullable<AvatarVariants['nSize']>, string> = {
  xs:      'size-6',
  sm:      'size-8',
  default: 'size-10',
  lg:      'size-12',
  xl:      'size-16',
};

export const SHAPE_CLASSES: Record<NonNullable<AvatarVariants['nShape']>, string> = {
  circle: 'rounded-full',
  square: 'rounded-md',
};

export type AvatarStatus = 'online' | 'offline' | 'away' | 'busy';

export const STATUS_COLOR: Record<AvatarStatus, string> = {
  online:  '#22c55e',
  offline: '#a1a1aa',
  away:    '#fbbf24',
  busy:    '#ef4444',
};

export const STATUS_LABEL: Record<AvatarStatus, string> = {
  online:  'Online',
  offline: 'Offline',
  away:    'Ausente',
  busy:    'Ocupado',
};

export * from './avatar.component';
export * from './avatar-group.component';
export * from './avatar.variants';
export * from './avatar.status';

